import React from 'react';
import { Link } from 'react-router-dom';
import { LayoutDashboard, PlusCircle, List, Home, Wallet, CreditCard } from 'lucide-react';

const Sidebar = () => {
  return (
    <aside className="sidebar">
      <h2><Wallet /> Finanças</h2>
      <nav>
        <Link to="/" className="nav-link">
          <Home size={20} /> Início
        </Link>
        
        <Link to="/lancamento" className="nav-link">
          <PlusCircle size={20} /> Novo Lançamento
        </Link>
        
        <Link to="/listagem" className="nav-link">
          <List size={20} /> Minhas Despesas
        </Link>

        {/* Novo link para a aba de cartões */}
        <Link to="/cartoes" className="nav-link">
          <CreditCard size={20} /> Meus Cartões
        </Link>
        
        <Link to="/dashboard" className="nav-link">
          <LayoutDashboard size={20} /> Dashboard
        </Link>
      </nav>
    </aside>
  );
};

export default Sidebar;
